module dram_cell (
    input clk,
    input we,
    input [15:0] data_in,
    output reg [15:0] data_out
);
    reg [15:0] cell_data;

    always @(posedge clk) begin
        if (we) begin
            cell_data <= data_in;
        end
    end

    always @(negedge clk) begin
        data_out <= cell_data;
    end
endmodule
